{
  "mode": "io",
  "tests": [
    {
      "name": "valid_user_authentication",
      "input": "{\"token\": \"valid_token\"}",
      "output": "{\"status\": \"success\", \"message\": \"User authenticated\"}",
      "notes": "Tests successful authentication with a valid token."
    },
    {
      "name": "invalid_user_authentication",
      "input": "{\"token\": \"invalid_token\"}",
      "output": "{\"status\": \"error\", \"message\": \"Invalid token\"}",
      "notes": "Tests response to an invalid authentication token."
    },
    {
      "name": "llm_response_streaming",
      "input": "{\"prompt\": \"What is AI?\"}",
      "output": "{\"response\": \"AI is...\", \"streaming\": true}",
      "notes": "Validates that the LLM can stream responses correctly."
    },
    {
      "name": "tool_selection_based_on_prompt",
      "input": "{\"prompt\": \"Use tool X for task Y\"}",
      "output": "{\"selected_tool\": \"tool_X\"}",
      "notes": "Ensures the agent selects the correct tool based on the prompt."
    },
    {
      "name": "conversation_memory_functionality",
      "input": "{\"previous_conversation\": [\"Hello\", \"How can I help you?\"]}",
      "output": "{\"response\": \"You can help me by...\"}",
      "notes": "Tests the conversation memory feature of the AI agent."
    },
    {
      "name": "tenant_validation_failure",
      "input": "{\"token\": \"valid_token\", \"tenant_id\": \"wrong_tenant\"}",
      "output": "{\"status\": \"error\", \"message\": \"User not in tenant\"}",
      "notes": "Tests the system's response when a user from a different tenant tries to access."
    },
    {
      "name": "mcp_gateway_connection_timeout",
      "input": "{\"action\": \"invoke_tool\"}",
      "output": "{\"status\": \"error\", \"message\": \"Connection timeout\"}",
      "notes": "Simulates a timeout scenario when connecting to the MCP Gateway."
    },
    {
      "name": "retry_on_throttling",
      "input": "{\"prompt\": \"Heavy load request\"}",
      "output": "{\"status\": \"success\", \"message\": \"Response after retry\"}",
      "notes": "Validates that the system retries on throttling and eventually succeeds."
    }
  ],
  "assumptions": "All tokens are JWTs and valid tokens are from the same Microsoft 365 tenant.",
  "notes": "Ensure to test both successful and failure scenarios for robust validation."
}
